import "../../Stylesheets/LandingPage/Rodape.css";

export default function Rodape() {
  const footer = ["Sobre Nós", "Política de Privacidade", "Termos e Condições"];
  return (
    <div className="h-14 bg-cinza">
      <div className="bg-branco w-full mt-">
        <ul className="items-center inline-flex h-24">
          {footer.map((item) => {
            return (
              <li className="text-base text-preto ml-[3vw] pr-[3vw]">{item}</li>
            );
          })}
        </ul>
      </div>
    </div>
  );
}
